function ModelPlayerSpace:UpdateRedPoint(info)
    local _redPointList = {}
    local bool = false
    self._redPointBadgeShow = bool
    if not info then
        return
    end
    for i, v in ipairs(info) do
        local arr =  string.split(v,"-")
        local type = tonumber(arr[1])
        local refId = tonumber(arr[2])
        local ref = gModelPlayer:GetRolePlayerHeadRefByRefId(refId)
        if ref and ref.uiShow == 1 then
            local list = _redPointList[type] or {}
            list[refId] = true
            _redPointList[type] = list
            bool = true
        end
    end
    self._redPointList = _redPointList
    self._redPointBadgeShow = bool

    FireEvent(EventNames.ON_ONENIGHT_ALL_REFRESH_EDIT_REDPOINT)
end

function ModelPlayerSpace:OnPersonaliseClickInfoResp(pb)--点击个性化信息
    local info = pb.info                    -- 新的红点信息列表
    self:UpdateRedPoint(info)
end

