function ModelPlayerSpace:OnAdventureLogInfoResp(pb)--冒险日志信息请求
    local infos = pb.infos                  --日志列表
    local playerId = pb.playerId            --请求他人生涯列表时使用
    self._logList = {}
    for i, v in ipairs(infos) do
        local info = StructAdventureInfo:New()
        info:CreateByPb(v)
        table.insert(self._logList,info)
    end
end

function ModelPlayerSpace:OnAdventureCareerInfoResp(pb)--冒险生涯信息请求
    local infos = pb.infos                  --生涯列表
    local shields = pb.shields              --屏蔽列表
    local playerId = pb.playerId            --请求他人生涯列表时使用
    self._careerInfo = {}
    local careerTypeList = {}
    local shieldList = {}

    for i, v in ipairs(infos) do
        local info = StructAdventureInfo:New()
        info:CreateByPb(v)
        local ref = self:GetRoleAdventureCareerRefByRefId(info.refId)
        if ref then
            info.careerRef = ref
            local subRef = self:GetRoleAdventureCareerSubtypeRefByRefId(ref.type)
            if subRef.FeatureOpenRefId == 0 or gModelFunctionOpen:CheckIsOpened(subRef.FeatureOpenRefId,false) then
                local typeList = careerTypeList[subRef.type] or {}
                local subList = typeList[ref.type] or {}
                table.insert(subList,info)
                subList.showType = ref.showType
                typeList[ref.type] = subList
                careerTypeList[subRef.type] = typeList
            end
        end
    end
    for i, v in ipairs(shields) do
        shieldList[v] = true
    end
    local _careerTypeList = {}
    for i, v in pairs(careerTypeList) do
        local list = {}
        for j, k in pairs(v) do
            k.typeId = j
            table.insert(list,k)
        end
        table.sort(list,function (a,b)
            local aR = self:GetRoleAdventureCareerSubtypeRefByRefId(a.typeId)
            local bR = self:GetRoleAdventureCareerSubtypeRefByRefId(b.typeId)
            return aR.sort < bR.sort
        end)
        _careerTypeList[i] = list
    end

    self._careerInfo.careerList = _careerTypeList
    self._careerInfo.shieldList = shieldList
end

function ModelPlayerSpace:OnAdventureCareerShieldResp(pb)--修改屏蔽列表
    local type = pb.type            --类型 0：取消屏蔽 1.屏蔽
    local refId = pb.refId          --屏蔽的类型Id
    local shields = pb.shields      --屏蔽列表
    local _shieldList = {}
    for i, v in ipairs(shields) do
        _shieldList[v] = true
    end
    self._careerInfo.shieldList = _shieldList
end

