function ModelPlayerSpace:GetCurrSpaceInfo()
    local _currInfo = self._currInfo
    local selfPlayerId = gModelPlayer:GetPlayerId()
    local isMe = true
    local playerInfo
    if not _currInfo then
        playerInfo = StructPlayerInfo:New()
        _currInfo = {
            playerId = selfPlayerId,
            playerInfo = playerInfo,
            fansCount = 0,
            isMe = isMe,
        }
        self._currInfo = _currInfo
    else
        playerInfo = _currInfo.playerInfo
    end
    playerInfo._playerId = selfPlayerId
    playerInfo._name = gModelPlayer:GetPlayerName()
    playerInfo.title = gModelPlayer:GetPlayerTitle()
    playerInfo._serverId = gModelPlayer:GetServerId()
    local guideInfo = gModelGuild:GetGuildInfo()
    playerInfo._guildName = guideInfo and guideInfo.guildName or ""
    return self._currInfo
end
