function ModelPlayerSpace:GetIsRedPointByType(type)
    local reds = self:GetRedPointListByType(type)
    local bool = false
    for i, v in pairs(reds) do
        if v then
            bool = true
            break
        end
    end
    return bool
end

function ModelPlayerSpace:GetIsRed()
    local _redPointList = self._redPointList
    if not _redPointList then
        return false
    end
    for i, v in pairs(_redPointList) do
        if i ~= ModelPlayerSpace.ROLE_MEDAL and i ~= ModelPlayerSpace.BUBBLE then
            for j, k in pairs(v) do
                if k then
                    return true
                end
            end
        end
    end
    return false
end

function ModelPlayerSpace:GetBadgeIsRed()
    local bool = false
    local _redPointList = self._redPointList
    if not _redPointList then
        return false
    end
    local typeList = _redPointList[ModelPlayerSpace.ROLE_MEDAL]
    if typeList then
        for j, k in pairs(typeList) do
            if k then
                bool = true
                break
            end
        end
    end
    return bool
end

function ModelPlayerSpace:GetPersonaliseRedPointStatusByRefId(refId)
    local redPointList = self._redPointList
    if not redPointList then return false end
    local ref = gModelPlayer:GetRolePlayerHeadRefByRefId(refId)
    if ref then
        local type = ref.type
        local typeList = redPointList[type]
        if typeList then
            return typeList[refId] or false
        end
    end
    return false
end

function ModelPlayerSpace:GetPersonaliseRedPointStatusListByType(type)
    local redPointList = self._redPointList
    if not redPointList then return {} end
    return redPointList[type] or {}
end

function ModelPlayerSpace:SetPersonaliseRedPointStatusByRefId(refId,status)
    status = status or false
    local redPointList = self._redPointList
    if not redPointList then return false end
    local ref = gModelPlayer:GetRolePlayerHeadRefByRefId(refId)
    if ref then
        local type = ref.type
        local typeList = redPointList[type]
        if typeList and typeList[refId] then
            typeList[refId] = status
        end
    end
    return false
end

function ModelPlayerSpace:SetRedPointBadgeShow()
