function ModelPlayerSpace:GetTodayZoneRed()
    local bool = self:GetIsRed()
    local todayZone = LPlayerPrefs.todayZone
    if todayZone == "false"then
        return false
    end
    return bool
end

function ModelPlayerSpace:SetTodayZoneRed(bool)
    local bools = bool and "true" or "false"
    local todayZone = LPlayerPrefs.todayZone
    if bools == todayZone then
        return
    end
    LPlayerPrefs.SetTodayZone(bools)
    FireEvent(EventNames.MAINCITY_ZONE_RED_UPDATE)
end

function ModelPlayerSpace:CheckBadgeRedPointStatus()
    local status = false
    if self._redPointBadgeShow then
        status = self:GetBadgeIsRed()
    end
    return status
end
function ModelPlayerSpace:GetMainCitySkinRed()
    local list = self:GetOneNightSkinRef()
    for i, v in ipairs(list) do
        local isAct = self:GetMainCitySkinByRefId(v.refId)
        if not isAct then
            local itemStr = v.item
            if string.isempty(itemStr) or itemStr == 0 or itemStr == "0" then
                return true
            end
            if not string.isempty(itemStr) then
                local item = LxDataHelper.ParseItem_3(v.item)
                local bagNum = gModelItem:GetNumByRefId(item.itemId)
                local isActivate = bagNum >= item.itemNum
                if isActivate then
                    return true
                end
            end
        end
    end
    return false
end
