    end)
    return list
end

function ModelPlayerSpace:GetRoleAgeListRefByRefId(refId)
    return GameTable.SnakeRoleAgeListRef[refId]
end

function ModelPlayerSpace:GetRoleProvinceListRef()
    local list = {}
    for i, v in pairs(GameTable.SnakeRoleProvinceListRef) do
        table.insert(list,v)
    end
    table.sort(list,function (a,b)
        return a.provinceId < b.provinceId
    end)
    return list
end

function ModelPlayerSpace:GetRoleProvinceListRefByRefId(refId)
    return GameTable.SnakeRoleProvinceListRef[refId]
end

function ModelPlayerSpace:GetRoleCityListRefByRefId(refId)
    local ref = GameTable.SnakeRoleCityListRef[refId]
    if not ref then
        printInfoNR2("配置缺失", string.format("GameTable.SnakeRoleCityListRef[%s]",refId ))
    end

    return ref
end

function ModelPlayerSpace:GetRoleTagPosByRefId(refId)
--    return GameTable.RoleTagPos[refId]
    
    return nil 
end

function ModelPlayerSpace:GetRoleCityListRef(provinceId)
    local list = {}
    for i, v in pairs(GameTable.SnakeRoleCityListRef) do
        if provinceId == v.provinceId then
            table.insert(list,v)
        end
    end
    table.sort(list,function (a,b)
        return a.refId < b.refId
    end)
    return list
end

function ModelPlayerSpace:GetRolePlayerHeadTypeRef()
    local list = {}
    for i, v in pairs(GameTable.SnakeRolePlayerHeadTypeRef) do
        local openId = v.openId
        if gModelFunctionOpen:CheckIsOpened(openId) then
            table.insert(list,v)
        end
    end
    table.sort(list,function (a,b)
        return a.sort < b.sort
    end)
    return list
end

function ModelPlayerSpace:GetRolePlayerHeadTypeRefByType(type)
    for i, v in pairs(GameTable.SnakeRolePlayerHeadTypeRef) do
        if type == v.type then
            return v
        end
    end
    return
end
