function ModelPlayerSpace:GetRoleAdventureImageTypeRefIsSortOpen(bigType,type)
    for i, v in pairs(GameTable.SnakeRoleAdventureImageTypeRef) do
        if bigType == v.bigType and v.type == type then
            return v.sortOpen
        end
    end
    return 0
end

